mapper.select:
SELECT s.id, s.workflow_id, s.name, s.description, s.schedule_type, s.cron_expression, s.interval_seconds, s.scheduled_time, s.input_params, s.status, s.last_run_at, s.next_run_at, s.run_count, s.created_by, s.created_at, s.updated_at, d.name AS workflow_name FROM workflow_schedule s LEFT JOIN workflow_definition d ON s.workflow_id = d.id
AND s.workflow_id = #{workflowId}
AND s.status = #{status}
AND (s.name LIKE CONCAT('%', #{keyword}, '%') OR d.name LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY s.created_at DESC

mapper.update:
UPDATE workflow_schedule
name = #{name}, description = #{description}, schedule_type = #{scheduleType}, cron_expression = #{cronExpression}, interval_seconds = #{intervalSeconds}, scheduled_time = #{scheduledTime}, input_params = #{inputParams}, next_run_at = #{nextRunAt}, updated_at = NOW()
WHERE id = #{id}

UPDATE workflow_schedule
SET last_run_at = #{lastRunAt}, next_run_at = #{nextRunAt}, run_count = #{runCount}, updated_at = NOW()
WHERE id = #{id}
